from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    if not triples:
        return ""

    # Predicates that describe a relationship where the object is the primary entity
    relational_predicates = {
        "leader", "capital", "currency", "anthem", "parentCompany", "location",
        "governingBody", "leaderTitle", "country", "isPartOf", "derivative",
        "recordLabel", "bandMember", "associatedBand/associatedMusicalArtist"
    }

    def format_triple(t: Triple) -> str:
        s, p, o = t.subject, t.predicate, t.object

        # Simple relational predicates where the object is the primary entity
        if p in relational_predicates:
            # e.g., "London is the capital of United Kingdom"
            return f"{o} is the {p} of {s}"

        # Temporal / biographic information
        if p in ("birthDate", "birthYear"):
            return f"{s} was born in {o}"
        if p in ("deathDate", "deathPlace"):
            return f"{s} died in {o}"
        if p == "birthPlace":
            return f"{s} was born in {o}"
        if p == "origin":
            return f"{s} originates from {o}"
        if p == "activeYearsStartYear":
            return f"{s} started their career in {o}"
        if p == "activeYearsEndYear":
            return f"{s} ended their career in {o}"

        # Professional / artistic attributes
        if p == "genre":
            # "Aaron Turner is a Black metal musician"
            return f"{s} is a {o} musician"
        if p == "instrument":
            # avoid unnecessary "the"
            return f"{s} plays {o}"
        if p == "occupation":
            return f"{s} works as {o}"
        if p == "nationality":
            return f"{s} is {o}"
        if p == "background":
            return f"{s} has a background as {o}"

        # Associations with bands / artists
        if p == "associatedBand/associatedMusicalArtist":
            # more natural phrasing
            return f"{s} performs with {o}"
        if p == "bandMember":
            return f"{o} is a member of {s}"
        if p == "recordLabel":
            return f"{s} is signed to {o}"

        # Music taxonomy relations
        if p == "musicFusionGenre":
            # "Death metal is a fusion of black metal"
            return f"{o} is a fusion of {s.lower()}"
        if p == "musicSubgenre":
            # "Christian alternative rock is a subgenre of alternative rock"
            return f"{o} is a subgenre of {s.lower()}"
        if p == "stylisticOrigin":
            # "New wave music is the stylistic origin of alternative rock"
            return f"{s} originates stylistically from {o}"
        if p == "derivative":
            # "Drum and bass is a derivative of hip hop music"
            return f"{o} is a derivative of {s.lower()}"

        # Default fallback for any other predicate
        return f"{s} {p} {o}"

    # Generate a clause for each triple
    clauses = [format_triple(t) for t in triples]

    # Combine clauses into a single fluent sentence
    if len(clauses) == 1:
        sentence = clauses[0] + "."
    else:
        sentence = ", ".join(clauses[:-1]) + ", and " + clauses[-1] + "."
    return sentence

# EVOLVE-BLOCK-END

